server {
    listen 8443 ssl;
    listen [::]:8443 ssl;
    server_name localhost;

    ssl_certificate     /etc/nginx/ssl/selfsigned.crt;
    ssl_certificate_key /etc/nginx/ssl/selfsigned.key;

    root /var/www/main;
    index index.html;

    location /dev/ {
        alias /var/www/dev/;
        index index.html;
        try_files $uri $uri/ /dev/index.html;
    }

    location / {
        try_files $uri $uri/ /index.html;
    }
}
